Bash(cat >> D:/GitHub/KitchenCopilot/Kitchen.Web/wwwroot/css/app.css << 'EOF'

/* ===== Kitchen Dark Theme ===== */
:root {
    --bg: #0F172A;
    --surface: #1E293B;
    --accent: #10B981;
    --accent-dark: #059669;
    --text: #F1F5F9;
    --muted: #94A3B8;
    --radius: 8px;
}

body { background: var\(--bg\); color: var\(--text\); }

.kitchen-layout {
    max-width: 900px;
    margin: 0 auto;
    padding: 1.5rem;
}

.kitchen-header { text-align: center; margin-bottom: 2rem; }
.kitchen-header h1 { color: var\(--accent\); font-size: 2.4rem; margin: 0; }
.kitchen-header p  { color: var\(--muted\); margin-top: .5rem; }

.kitchen-main { display: flex; flex-direction: column; gap: 2rem; }

/* Buttons */
.btn-primary, .btn-secondary, .btn-accent {
    padding: .6rem 1.4rem;
    border: none;
    border-radius: var\(--radius\);
    cursor: pointer;
    font-size: 1rem;
    transition: background .2s;
}
.btn-primary  { background: var\(--accent\); color: #fff; }
.btn-primary:hover  { background: var\(--accent-dark\); }
.btn-secondary { background: var\(--surface\); color: var\(--text\); border: 1px solid #334155; }
.btn-accent { background: var\(--accent\); color: #fff; margin-top: 1rem; }

/* Fridge scan */
.fridge-scan { background: var\(--surface\); border-radius: var\(--radius\); padding: 1.5rem; }
.fridge-scan h2 { color: var\(--accent\); margin-top: 0; }
.capture-controls { display: flex; gap: 1rem; flex-wrap: wrap; margin-bottom: 1rem; }
.status { color: var\(--muted\); font-style: italic; }

/* Ingredient chips */
.ingredient-chips { display: flex; flex-wrap: wrap; gap: .5rem; margin: 1rem 0; }
.chip {
    background: #0D3D2E;
    border: 1px solid var\(--accent\);
    color: var\(--accent\);
    border-radius: 999px;
    padding: .3rem .8rem;
    font-size: .9rem;
}
.chip small { color: var\(--muted\); margin-left: .3rem; }

/* Recipe display */
.recipe-display { background: var\(--surface\); border-radius: var\(--radius\); padding: 1.5rem; min-height: 120px; }
.streaming-indicator { color: var\(--accent\); font-style: italic; margin-bottom: 1rem; }
.recipe-content { line-height: 1.7; }
.recipe-content h2 { color: var\(--accent\); }
.placeholder { color: var\(--muted\); font-style: italic; }
EOF)
